import heapq
from .core import create_task, TaskError


class Scheduler:
    """Priority-based task scheduler."""

    def __init__(self):
        self._queue = []
        self._counter = 0

    def submit(self, name, func, priority=0, tags=None):
        """Submit a new task for scheduling."""
        task = create_task(name, func, priority=priority, tags=tags)
        self._counter += 1
        heapq.heappush(self._queue, (-task["priority"], self._counter, task))
        return task

    def next(self):
        """Get the next task to execute."""
        if not self._queue:
            raise TaskError("scheduler", "No tasks in queue")
        _, _, task = heapq.heappop(self._queue)
        return task

    def pending_count(self):
        return len(self._queue)

