import time
from .core import TaskError


class RetryPolicy:
    """Retry failed tasks with configurable backoff."""

    def __init__(self, max_retries=3, backoff_factor=1.0):
        self.max_retries = max_retries
        self.backoff_factor = backoff_factor

    def execute_with_retry(self, task):
        """Execute task with retries on TaskError."""
        last_error = None
        for attempt in range(self.max_retries + 1):
            try:
                result = task["func"]()
                task["status"] = "completed"
                task["result"] = result
                return result
            except Exception as e:
                last_error = e
                if isinstance(e, TaskError):
                    task["error"] = e.message
                else:
                    task["error"] = str(e)
                if attempt < self.max_retries:
                    time.sleep(self.backoff_factor * (2 ** attempt) * 0.001)
        raise TaskError(task["id"], f"Failed after {self.max_retries + 1} attempts", cause=last_error)

