from .core import TaskError


class HookRegistry:
    """Register callbacks for task lifecycle events."""

    def __init__(self):
        self._hooks = {"before": [], "after": [], "error": []}

    def on_before(self, callback):
        self._hooks["before"].append(callback)
        return callback

    def on_after(self, callback):
        self._hooks["after"].append(callback)
        return callback

    def on_error(self, callback):
        self._hooks["error"].append(callback)
        return callback

    def fire_before(self, task):
        for hook in self._hooks["before"]:
            hook(task)

    def fire_after(self, task, result):
        for hook in self._hooks["after"]:
            hook(task, result)

    def fire_error(self, task, error):
        for hook in self._hooks["error"]:
            hook(task, error)

    def execute_with_hooks(self, task):
        """Run a task with before/after/error hooks."""
        self.fire_before(task)
        try:
            result = task["func"]()
            task["status"] = "completed"
            task["result"] = result
            self.fire_after(task, result)
            return result
        except Exception as e:
            err = TaskError(task["id"], str(e), cause=e)
            task["status"] = "failed"
            self.fire_error(task, err)
            raise err

