from .core import TaskError


class Monitor:
    """Track task execution statistics."""

    def __init__(self):
        self.total = 0
        self.succeeded = 0
        self.failed = 0
        self.errors = []

    def record_success(self, task):
        self.total += 1
        self.succeeded += 1

    def record_failure(self, task, error):
        """Record a task failure."""
        self.total += 1
        self.failed += 1
        if isinstance(error, TaskError):
            self.errors.append({"task_id": error.task_id, "message": error.message})
        else:
            self.errors.append({"task_id": task["id"], "message": str(error)})

    def summary(self):
        return {
            "total": self.total,
            "succeeded": self.succeeded,
            "failed": self.failed,
            "error_count": len(self.errors),
        }
